#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 2e6 + 5;

string s;
int dp[N], t[N];

signed main()
{
    cin.tie(0) -> sync_with_stdio(false);
    int n, ans = 0;
    cin >> n >> s;
    s = "#" + s;
    for(int i = 1; i <= n; i++)
    {
        int j = i - 1;
        while(j > 0 && s[j] != s[i]) j = t[j] - 1;
        if(s[i] == s[j]) t[i] = j;
        if(t[i]) dp[i] = dp[t[i] - 1] + 1, ans += dp[i];
    }
    cout << ans;
}
